import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Typography, List, ListItem, ListItemText, CircularProgress } from '@mui/material';

export default function DeliveryList() {
  const [deliveries, setDeliveries] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    axios.get('/api/deliveries')
      .then(response => {
        setDeliveries(response.data);
        setLoading(false);
      })
      .catch(error => {
        setError('Failed to load deliveries');
        setLoading(false);
      });
  }, []);

  if (loading) return <CircularProgress />;
  if (error) return <Typography color="error">{error}</Typography>;
  if (deliveries.length === 0) return <Typography>No deliveries found.</Typography>;

  return (
    <div>
      <Typography variant="h6" gutterBottom>Deliveries</Typography>
      <List>
        {deliveries.map(delivery => (
          <ListItem key={delivery.id}>
            <ListItemText
              primary={`Vendor ID: ${delivery.vendorId} - Status: ${delivery.status}`}
              secondary={`Scheduled: ${new Date(delivery.scheduledTime).toLocaleString()}`}
            />
          </ListItem>
        ))}
      </List>
    </div>
  );
}
