import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Typography, List, ListItem, ListItemText, CircularProgress } from '@mui/material';

export default function EventList() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    axios.get('/api/events')
      .then(response => {
        setEvents(response.data);
        setLoading(false);
      })
      .catch(error => {
        setError('Failed to load events');
        setLoading(false);
      });
  }, []);

  if (loading) return <CircularProgress />;
  if (error) return <Typography color="error">{error}</Typography>;
  if (events.length === 0) return <Typography>No events found.</Typography>;

  return (
    <div>
      <Typography variant="h6" gutterBottom>Events</Typography>
      <List>
        {events.map(event => (
          <ListItem key={event.id}>
            <ListItemText
              primary={event.title}
              secondary={`${new Date(event.startTime).toLocaleString()} - ${new Date(event.endTime).toLocaleString()}`}
            />
          </ListItem>
        ))}
      </List>
    </div>
  );
}
