import React, { useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import { Container, AppBar, Toolbar, Typography, Button } from '@mui/material';
import VendorList from './components/VendorList';
import EventList from './components/EventList';
import DeliveryList from './components/DeliveryList';
import Login from './components/Login';

function App() {
  const [token, setToken] = useState(null);

  if (!token) {
    return <Login onLogin={setToken} />;
  }

  return (
    <Router>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
            Campus Operations Tracker
          </Typography>
          <Button color="inherit" component={Link} to="/vendors">Vendors</Button>
          <Button color="inherit" component={Link} to="/events">Events</Button>
          <Button color="inherit" component={Link} to="/deliveries">Deliveries</Button>
        </Toolbar>
      </AppBar>
      <Container sx={{ mt: 2 }}>
        <Routes>
          <Route path="/vendors" element={<VendorList />} />
          <Route path="/events" element={<EventList />} />
          <Route path="/deliveries" element={<DeliveryList />} />
          <Route path="/" element={<Typography variant="h5">Welcome to the Campus Operations Tracker</Typography>} />
        </Routes>
      </Container>
    </Router>
  );
}

export default App;

