import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Typography, List, ListItem, ListItemText, CircularProgress } from '@mui/material';

export default function VendorList() {
  const [vendors, setVendors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    axios.get('/api/vendors')
      .then(response => {
        setVendors(response.data);
        setLoading(false);
      })
      .catch(error => {
        setError('Failed to load vendors');
        setLoading(false);
      });
  }, []);

  if (loading) return <CircularProgress />;
  if (error) return <Typography color="error">{error}</Typography>;
  if (vendors.length === 0) return <Typography>No vendors found.</Typography>;

  return (
    <div>
      <Typography variant="h6" gutterBottom>Vendors</Typography>
      <List>
        {vendors.map(vendor => (
          <ListItem key={vendor.id}>
            <ListItemText primary={vendor.name} secondary={`${vendor.contactName} - ${vendor.phone || 'No phone'}`} />
          </ListItem>
        ))}
      </List>
    </div>
  );
}
